import React from "react";
import { getAllBlogs } from "@/sanity/lib/queries";
import BlogHero from "@/components/blog/BlogHero";
import BlogCard from "@/components/blog/BlogCard";

export const metadata = {
  title: "Blog | Wefik",
  description:
    "Explore our latest thoughts on digital innovation, design trends, and the future of web experiences.",
};

export default async function BlogListingPage() {
  const posts = await getAllBlogs();

  return (
    <main className="bg-bg-primary min-h-screen">
      <BlogHero />

      <section className="relative pb-24 md:pb-32">
        <div className="mx-auto max-w-7xl px-6">
          {posts.length > 0 ? (
            <div className="grid grid-cols-1 gap-10 md:grid-cols-2 lg:grid-cols-3">
              {posts.map((post) => (
                <BlogCard key={post.slug.current} post={post} />
              ))}
            </div>
          ) : (
            <div className="border-border/10 flex min-h-[400px] flex-col items-center justify-center rounded-3xl border bg-white/2 px-6 text-center">
              <h2 className="text-text-primary text-2xl font-bold">
                No posts found yet.
              </h2>
              <p className="text-text-muted mt-4 max-w-md">
                We're crafting some amazing stories. Check back soon for our
                latest updates!
              </p>
            </div>
          )}
        </div>
      </section>

      <div className="pointer-events-none fixed inset-0 z-0 opacity-20">
        <div className="border-border/10 absolute top-[10%] left-0 h-px w-full border-t" />
        <div className="border-border/10 absolute top-[90%] left-0 h-px w-full border-t" />
      </div>
    </main>
  );
}

import React from "react";
import { notFound } from "next/navigation";
import { getJobBySlug, getOpenJobs } from "@/sanity/lib/queries";
import { format } from "date-fns";
import {
  ArrowLeft,
  MapPin,
  Briefcase,
  Clock,
  CheckCircle2,
} from "lucide-react";
import Link from "next/link";
import ApplySection from "@/components/careers/ApplySection";

export async function generateMetadata({ params }) {
  const { slug } = await params;
  const job = await getJobBySlug(slug);
  if (!job) return {};

  return {
    title: `${job.title} | Careers at Wefik`,
    description: job.description,
  };
}

export async function generateStaticParams() {
  const jobs = await getOpenJobs();
  return jobs.map((job) => ({
    slug: job.slug.current,
  }));
}

export default async function JobDetailPage({ params }) {
  const { slug } = await params;
  const job = await getJobBySlug(slug);

  if (!job) {
    notFound();
  }

  return (
    <article className="bg-bg-primary min-h-screen pt-32 pb-32 md:pt-48">
      <div className="mx-auto max-w-4xl px-6">
        <Link
          href="/careers"
          className="text-accent mb-12 inline-flex items-center gap-2 text-xs font-black tracking-[0.3em] uppercase transition-transform hover:-translate-x-2"
        >
          <ArrowLeft size={16} strokeWidth={3} />
          Back to Careers
        </Link>

        <header className="mb-16">
          <h1 className="font-display text-text-primary text-5xl leading-tight font-black tracking-tighter md:text-8xl">
            {job.title}
          </h1>

          <div className="text-text-muted mt-12 flex flex-wrap gap-8 text-sm font-bold tracking-[0.2em] uppercase">
            <div className="flex items-center gap-3">
              <Briefcase size={20} className="text-accent" />
              {job.type}
            </div>
            <div className="flex items-center gap-3">
              <MapPin size={20} className="text-accent" />
              {job.location}
            </div>
            <div className="flex items-center gap-3">
              <Clock size={20} className="text-accent" />
              Posted on {format(new Date(job.postedAt), "MMMM dd, yyyy")}
            </div>
          </div>
        </header>

        <div className="grid grid-cols-1 gap-16">
          <section>
            <h2 className="text-text-primary mb-8 text-3xl font-black tracking-tighter">
              About the role
            </h2>
            <p className="text-text-muted text-lg leading-relaxed md:text-xl">
              {job.description}
            </p>
          </section>

          {job.responsibilities && job.responsibilities.length > 0 && (
            <section>
              <h2 className="text-text-primary mb-8 text-3xl font-black tracking-tighter">
                What you'll do
              </h2>
              <ul className="space-y-4">
                {job.responsibilities.map((item, idx) => (
                  <li key={idx} className="text-text-muted flex gap-4 text-lg">
                    <CheckCircle2
                      size={24}
                      className="text-accent mt-1 shrink-0"
                    />
                    {item}
                  </li>
                ))}
              </ul>
            </section>
          )}

          {job.requirements && job.requirements.length > 0 && (
            <section>
              <h2 className="text-text-primary mb-8 text-3xl font-black tracking-tighter">
                What you'll need
              </h2>
              <ul className="space-y-4">
                {job.requirements.map((item, idx) => (
                  <li key={idx} className="text-text-muted flex gap-4 text-lg">
                    <CheckCircle2
                      size={24}
                      className="text-accent mt-1 shrink-0"
                    />
                    {item}
                  </li>
                ))}
              </ul>
            </section>
          )}

          <ApplySection jobTitle={job.title} applyUrl={job.applyUrl} />
        </div>
      </div>
    </article>
  );
}

import { PortableText } from "@portabletext/react";
import Image from "next/image";
import { urlFor } from "@/sanity/lib/image";

const components = {
  types: {
    image: ({ value }) => (
      <figure className="my-12 overflow-hidden rounded-2xl border border-white/5 bg-neutral-900">
        <div className="relative aspect-video w-full">
          <Image
            src={urlFor(value).url()}
            alt={value.alt || "Blog image"}
            fill
            className="object-cover"
          />
        </div>
        {value.caption && (
          <figcaption className="text-text-muted border-t border-white/5 bg-white/2 px-6 py-4 text-center text-sm italic">
            {value.caption}
          </figcaption>
        )}
      </figure>
    ),
  },
  block: {
    h2: ({ children }) => (
      <h2 className="font-display text-text-primary mt-20 mb-8 text-3xl font-bold tracking-tight md:text-5xl">
        {children}
      </h2>
    ),
    h3: ({ children }) => (
      <h3 className="font-display text-text-primary mt-16 mb-6 text-2xl font-bold tracking-tight md:text-3xl">
        {children}
      </h3>
    ),
    normal: ({ children }) => (
      <p className="text-text-muted mt-8 text-lg leading-relaxed md:text-xl">
        {children}
      </p>
    ),
    blockquote: ({ children }) => (
      <blockquote className="border-accent/40 bg-accent/5 text-text-primary my-12 border-l-4 px-8 py-8 text-2xl italic">
        "{children}"
      </blockquote>
    ),
  },
  list: {
    bullet: ({ children }) => (
      <ul className="text-text-muted mt-8 list-disc space-y-4 pl-8 text-lg md:text-xl">
        {children}
      </ul>
    ),
    number: ({ children }) => (
      <ol className="text-text-muted mt-8 list-decimal space-y-4 pl-8 text-lg md:text-xl">
        {children}
      </ol>
    ),
  },
  marks: {
    link: ({ children, value }) => {
      const rel = !value.href.startsWith("/")
        ? "noreferrer noopener"
        : undefined;
      return (
        <a
          href={value.href}
          rel={rel}
          className="text-accent decoration-accent/30 hover:decoration-accent underline underline-offset-4 transition-colors"
        >
          {children}
        </a>
      );
    },
    strong: ({ children }) => (
      <strong className="text-text-primary font-bold">{children}</strong>
    ),
    code: ({ children }) => (
      <code className="text-accent rounded-md border border-white/10 bg-white/5 px-1.5 py-0.5 font-mono text-sm">
        {children}
      </code>
    ),
  },
};

export default function PortableTextContent({ value }) {
  if (!value) return null;
  return (
    <div className="prose prose-invert max-w-none">
      <PortableText value={value} components={components} />
    </div>
  );
}

